// build-gtm-plan — Validate Upstream Inputs
// Checks all required upstream artifacts are present and well-formed.
//
// CLOUD MODE: all data arrives inline via n8n pipeline. No filesystem access.

let cloudMode = false;
try { require('fs'); } catch (_e) { cloudMode = true; }

const input = $input.first().json;
const contentStrategy   = input.content_strategy;
const offerArchitecture = input.offer_architecture;
const strategySynthesis = input.strategy_synthesis;
const marketIntelligence = input.market_intelligence;
const intakePayload     = input.normalized_intake_payload;
const runtimeConfig     = input.runtime_config;
const projectId         = input.project_id;

if (!cloudMode && runtimeConfig && runtimeConfig.cloud_mode) cloudMode = true;

// Required presence checks
if (!contentStrategy) {
  throw new Error('MISSING_ARTIFACT: content_strategy is required. Run build-content-strategy first.');
}
if (!contentStrategy.messaging_hierarchy || !contentStrategy.messaging_hierarchy.primary_message) {
  throw new Error('MISSING_ARTIFACT: content_strategy.messaging_hierarchy.primary_message is required.');
}
if (!offerArchitecture) {
  throw new Error('MISSING_ARTIFACT: offer_architecture is required. Run build-offer-architecture first.');
}
if (!offerArchitecture.core_offer || !offerArchitecture.core_offer.headline) {
  throw new Error('MISSING_ARTIFACT: offer_architecture.core_offer.headline is required.');
}
if (!strategySynthesis) {
  throw new Error('MISSING_ARTIFACT: strategy_synthesis is required. Run build-strategy-synthesis first.');
}
if (!intakePayload) {
  throw new Error('MISSING_ARTIFACT: normalized_intake_payload is required. Run intake-store-input first.');
}
if (!runtimeConfig) {
  throw new Error('MISSING_RUNTIME_CONFIG: runtime_config is required.');
}
if (!projectId) {
  throw new Error('MISSING_INPUT: project_id is required.');
}

console.log('build-gtm-plan: inputs validated. cloud=' + cloudMode + ' project=' + projectId);

return [{
  json: {
    project_id:                projectId,
    runtime_config:            runtimeConfig,
    content_strategy:          contentStrategy,
    offer_architecture:        offerArchitecture,
    strategy_synthesis:        strategySynthesis,
    market_intelligence:       marketIntelligence || null,
    normalized_intake_payload: intakePayload,
    cloud_mode:                cloudMode,
  },
}];

// build-gtm-plan — Build LLM Synthesis Prompt
// Extracts signals from content_strategy + offer_architecture + strategy_synthesis
// and assembles a structured prompt for GTM plan generation.
//
// Evidence boundary: LLM inference from internal signals only.
// All outputs are planning hypotheses requiring human verification.

const input     = $input.first().json;
const cs        = input.content_strategy;
const oa        = input.offer_architecture;
const ss        = input.strategy_synthesis;
const mi        = input.market_intelligence || {};
const ip        = input.normalized_intake_payload;
const cloudMode = input.cloud_mode || false;

// ─── Extract Content Strategy signals ────────────────────────────────────────
const mh              = cs.messaging_hierarchy || {};
const primaryMessage  = mh.primary_message || '';
const supportMsgs     = (mh.supporting_messages || []).slice(0, 4);
const proofStatements = (mh.proof_statements || []).slice(0, 3);
const pillars         = (cs.content_pillars || []).slice(0, 4).map(function(p) {
  return p.pillar + (p.rationale ? ': ' + p.rationale.slice(0, 80) : '');
});
const ev              = cs.editorial_voice || {};
const tone            = ev.tone || 'technical-trustworthy';
const ps              = cs.page_strategy || {};
const homepageAngle   = ps.homepage_angle || '';
const seo             = cs.seo_content_plan || {};
const kwClusters      = (seo.primary_keyword_clusters || []).slice(0, 4);
const faqClusters     = (seo.faq_topic_clusters || []).slice(0, 3);

// ─── Extract Offer Architecture signals ──────────────────────────────────────
const coreOffer       = oa.core_offer || {};
const offerHeadline   = coreOffer.headline || '';
const targetBuyer     = coreOffer.target_buyer || '';
const pricingTier     = (oa.pricing_logic || {}).tier || 'unknown';
const bulkPricing     = (oa.pricing_logic || {}).bulk_pricing || false;
const anchorStrategy  = (oa.pricing_logic || {}).anchor_strategy || '';
const offerNarrative  = oa.offer_narrative || '';
const bundles         = (oa.bundle_opportunities || []).slice(0, 3).map(function(b) { return b.name; });
const upsellPaths     = (oa.upsell_paths || []).slice(0, 3).map(function(u) {
  return u.from + ' -> ' + u.to;
});

// ─── Extract Strategy Synthesis signals ──────────────────────────────────────
const positioningFocus = ss.positioning_focus || {};
const posAngle         = typeof positioningFocus === 'string' ? positioningFocus
  : (positioningFocus.primary_angle || JSON.stringify(positioningFocus));
const opportunities    = (ss.opportunity_priorities || []).slice(0, 4).map(function(o) {
  return typeof o === 'string' ? o : (o.opportunity || JSON.stringify(o));
});
const risks            = (ss.risk_priorities || []).slice(0, 3).map(function(r) {
  return typeof r === 'string' ? r : (r.risk || JSON.stringify(r));
});
const growthThesis     = ss.growth_thesis || {};
const growthStatement  = typeof growthThesis === 'string' ? growthThesis : (growthThesis.statement || '');
const gtmImplications  = (ss.gtm_implications || []).slice(0, 4);

// ─── Extract intake signals ───────────────────────────────────────────────────
const vertical         = ip.vertical || 'unknown';
const pricePositioning = ip.price_positioning || 'unknown';
const primaryMarket    = ip.primary_market || 'DE';
const primaryLanguage  = ip.primary_language || 'de';
const projectName      = ip.project_name || ip.project_id || 'the store';

// ─── Extract market intelligence (optional) ───────────────────────────────────
const audienceSegments = (mi.audience_segments || []).slice(0, 3).map(function(s) {
  return typeof s === 'string' ? s : ((s.segment_name || 'segment') + (s.description ? ': ' + String(s.description).slice(0, 80) : ''));
});
const competitorTypes  = (mi.competitor_types || []).slice(0, 3).map(function(c) {
  return typeof c === 'string' ? c : JSON.stringify(c);
});
const trustFactors     = (mi.trust_factors || []).slice(0, 3).map(function(t) {
  return typeof t === 'string' ? t : (t.factor || JSON.stringify(t));
});
const purchaseMotivators = (mi.purchase_motivators || []).slice(0, 3).map(function(m) {
  return typeof m === 'string' ? m : (m.motivator || JSON.stringify(m));
});

// ─── Build prompt using array accumulation ────────────────────────────────────
var lines = [];

lines.push('You are a senior go-to-market strategist building the GTM plan for a new Shopify store.');
lines.push('Based on the strategic, offer, and content intelligence below, generate a practical and execution-oriented GTM plan.');
lines.push('');
lines.push('## Store Context');
lines.push('Project: ' + projectName);
lines.push('Vertical: ' + vertical);
lines.push('Price positioning: ' + pricePositioning + (bulkPricing ? ' (bulk pricing available)' : ''));
lines.push('Primary market: ' + primaryMarket);
lines.push('Primary language: ' + primaryLanguage);
lines.push('');
lines.push('## Core Offer');
lines.push('Headline: ' + offerHeadline);
lines.push('Target buyer: ' + targetBuyer);
lines.push('Pricing tier: ' + pricingTier);
if (anchorStrategy) lines.push('Anchor strategy: ' + anchorStrategy);
if (offerNarrative) lines.push('Offer narrative: ' + offerNarrative.slice(0, 300));
if (bundles.length > 0) lines.push('Bundles: ' + bundles.join(', '));
if (upsellPaths.length > 0) lines.push('Upsell paths: ' + upsellPaths.join(', '));
lines.push('');
lines.push('## Messaging');
lines.push('Primary message: ' + primaryMessage);
if (supportMsgs.length > 0) lines.push('Supporting messages: ' + supportMsgs.join(' | '));
if (proofStatements.length > 0) lines.push('Proof statements: ' + proofStatements.join(' | '));
if (homepageAngle) lines.push('Homepage angle: ' + homepageAngle);
lines.push('Editorial tone: ' + tone);
lines.push('');
lines.push('## Strategic Intelligence');
lines.push('Positioning focus: ' + posAngle);
if (growthStatement) lines.push('Growth thesis: ' + growthStatement.slice(0, 300));
if (pillars.length > 0) {
  lines.push('Content pillars:');
  pillars.forEach(function(p) { lines.push('  - ' + p); });
}
if (kwClusters.length > 0) lines.push('Primary keyword clusters: ' + kwClusters.join(', '));
if (faqClusters.length > 0) lines.push('FAQ clusters: ' + faqClusters.join(', '));
if (opportunities.length > 0) {
  lines.push('');
  lines.push('Key opportunities:');
  opportunities.forEach(function(o, i) { lines.push((i+1) + '. ' + o); });
}
if (risks.length > 0) {
  lines.push('');
  lines.push('Key risks:');
  risks.forEach(function(r, i) { lines.push((i+1) + '. ' + r); });
}
if (gtmImplications.length > 0) {
  lines.push('');
  lines.push('GTM implications from strategy:');
  gtmImplications.forEach(function(g) { lines.push('  - ' + (typeof g === 'string' ? g : JSON.stringify(g))); });
}
if (audienceSegments.length > 0) {
  lines.push('');
  lines.push('Audience segments:');
  audienceSegments.forEach(function(s) { lines.push('  - ' + s); });
}
if (competitorTypes.length > 0) lines.push('Competitor types: ' + competitorTypes.join(', '));
if (trustFactors.length > 0) lines.push('Trust factors: ' + trustFactors.join(', '));
if (purchaseMotivators.length > 0) lines.push('Purchase motivators: ' + purchaseMotivators.join(', '));
lines.push('');
lines.push('## Output Requirements');
lines.push('Return a JSON object with exactly this structure (pure JSON, no markdown fences):');
lines.push('{');
lines.push('  "launch_sequence": {');
lines.push('    "phase_1": {');
lines.push('      "name": "Phase name (e.g. Foundation)",');
lines.push('      "duration": "e.g. Weeks 1-4",');
lines.push('      "objectives": ["objective 1", "objective 2"],');
lines.push('      "key_actions": ["action 1", "action 2", "action 3"],');
lines.push('      "success_metrics": ["metric 1", "metric 2"]');
lines.push('    },');
lines.push('    "phase_2": {');
lines.push('      "name": "Phase name (e.g. Launch & Acquire)",');
lines.push('      "duration": "e.g. Weeks 5-12",');
lines.push('      "objectives": ["objective 1", "objective 2"],');
lines.push('      "key_actions": ["action 1", "action 2"],');
lines.push('      "success_metrics": ["metric 1", "metric 2"]');
lines.push('    },');
lines.push('    "phase_3": {');
lines.push('      "name": "Phase name (e.g. Scale)",');
lines.push('      "duration": "e.g. Month 4+",');
lines.push('      "objectives": ["objective 1"],');
lines.push('      "key_actions": ["action 1"],');
lines.push('      "success_metrics": ["metric 1"]');
lines.push('    }');
lines.push('  },');
lines.push('  "channel_strategy": [');
lines.push('    {');
lines.push('      "channel": "Channel name (e.g. Organic Search / SEO)",');
lines.push('      "priority": "primary",');
lines.push('      "rationale": "Why this channel fits",');
lines.push('      "estimated_impact": "Expected contribution",');
lines.push('      "budget_signal": "Relative budget allocation signal"');
lines.push('    }');
lines.push('  ],');
lines.push('  "acquisition_priorities": [');
lines.push('    {');
lines.push('      "tactic": "Tactic name",');
lines.push('      "rationale": "Why prioritised",');
lines.push('      "timeline": "When to execute",');
lines.push('      "owner": "Who is responsible (e.g. Marketing team)"');
lines.push('    }');
lines.push('  ],');
lines.push('  "campaign_angles": [');
lines.push('    { "angle": "Campaign angle", "rationale": "Why it works", "channel_fit": ["SEO", "Email"] }');
lines.push('  ],');
lines.push('  "funnel_recommendations": {');
lines.push('    "top_of_funnel": "Strategy for awareness",');
lines.push('    "mid_funnel": "Strategy for consideration and engagement",');
lines.push('    "bottom_funnel": "Strategy for conversion"');
lines.push('  },');
lines.push('  "kpis": [');
lines.push('    { "kpi": "KPI name", "target": "Target value", "timeframe": "When to measure" }');
lines.push('  ],');
lines.push('  "test_plan": [');
lines.push('    { "test": "What to test", "hypothesis": "Expected outcome", "success_criteria": "How to measure" }');
lines.push('  ],');
lines.push('  "execution_risks": [');
lines.push('    { "risk": "Risk description", "likelihood": "high/medium/low", "mitigation": "How to mitigate" }');
lines.push('  ],');
lines.push('  "gtm_narrative": "2-4 paragraph executive summary of the GTM plan.",');
lines.push('  "risk_flags": ["Risk or assumption that could derail the plan"],');
lines.push('  "validation_questions": ["Question needing merchant input before launch"]');
lines.push('}');
lines.push('');
lines.push('Rules:');
lines.push('- channel_strategy: minimum 2 channels, include at least one primary');
lines.push('- priority values must be exactly: primary, secondary, or exploratory');
lines.push('- acquisition_priorities: minimum 2 tactics');
lines.push('- campaign_angles: minimum 2 angles grounded in the messaging above');
lines.push('- kpis: minimum 3 KPIs with specific targets');
lines.push('- test_plan: minimum 2 tests');
lines.push('- execution_risks: minimum 2 risks');
lines.push('- gtm_narrative: minimum 2 paragraphs, must reference the specific offer and audience');
lines.push('- All recommendations grounded in the strategic intelligence above');
lines.push('- Return pure JSON only — no markdown, no commentary outside the JSON');

const prompt = lines.join('\n');

return [{
  json: {
    llm_prompt:                prompt,
    project_id:                input.project_id,
    runtime_config:            input.runtime_config,
    content_strategy:          cs,
    offer_architecture:        oa,
    strategy_synthesis:        ss,
    normalized_intake_payload: ip,
    cloud_mode:                cloudMode,
  },
}];

// build-gtm-plan — Parse, Validate, and Write
//
// Steps:
//   1. Parse LLM JSON object response
//   2. Inline schema validation (required fields, structure checks)
//   3. Return gtm_plan inline with runtime envelope
//
// CLOUD MODE: fully compatible. No AJV, no filesystem write.

function buildRunId() {
  const ts = new Date().toISOString().replace(/[-:T.Z]/g, '').slice(0, 14);
  const rand = Math.random().toString(36).slice(2, 6);
  return 'run-' + ts + '-' + rand;
}

let cloudMode = false;
try { require('fs'); } catch (_e) { cloudMode = true; }

const llmOutput = $input.first().json;
const upstream  = $node['Build LLM Synthesis Prompt'].json;

if (!cloudMode && upstream.cloud_mode) cloudMode = true;
if (!cloudMode && upstream.runtime_config && upstream.runtime_config.cloud_mode) cloudMode = true;

const projectId     = upstream.project_id;
const runtimeConfig = upstream.runtime_config;

// ─── Step 1: Parse LLM response ──────────────────────────────────────────────
const rawText = (llmOutput.message && llmOutput.message.content)
  ? llmOutput.message.content
  : (typeof llmOutput === 'string' ? llmOutput : JSON.stringify(llmOutput));

let gtmPlan;
try {
  let cleaned = rawText.trim();
  if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();
  }
  const parsed = JSON.parse(cleaned);
  if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
    gtmPlan = parsed;
  } else {
    throw new Error('Expected a JSON object at root, got: ' + typeof parsed);
  }
} catch (err) {
  throw new Error(
    'LLM_PARSE_ERROR: Failed to parse LLM response as JSON object: ' + err.message +
    '. Raw response (first 500 chars): ' + String(rawText).slice(0, 500)
  );
}

// ─── Step 2: Inline schema validation ────────────────────────────────────────
const cloudWarnings = [];

// Required top-level fields
const REQUIRED = ['launch_sequence', 'channel_strategy', 'acquisition_priorities', 'gtm_narrative'];
for (const f of REQUIRED) {
  if (!gtmPlan[f]) {
    throw new Error('SCHEMA_VIOLATION: gtm_plan.' + f + ' is required.');
  }
}

// launch_sequence required sub-phases
if (!gtmPlan.launch_sequence.phase_1) {
  throw new Error('SCHEMA_VIOLATION: launch_sequence.phase_1 is required.');
}
if (!gtmPlan.launch_sequence.phase_2) {
  throw new Error('SCHEMA_VIOLATION: launch_sequence.phase_2 is required.');
}
for (const phase of ['phase_1', 'phase_2']) {
  const p = gtmPlan.launch_sequence[phase];
  if (!p.name || !Array.isArray(p.objectives) || p.objectives.length === 0) {
    throw new Error('SCHEMA_VIOLATION: launch_sequence.' + phase + ' must have name and objectives.');
  }
}

// channel_strategy: array, min 1, valid priority enum
if (!Array.isArray(gtmPlan.channel_strategy) || gtmPlan.channel_strategy.length < 1) {
  throw new Error('SCHEMA_VIOLATION: channel_strategy must be a non-empty array.');
}
const PRIORITY_ENUM = ['primary', 'secondary', 'exploratory'];
for (let i = 0; i < gtmPlan.channel_strategy.length; i++) {
  const c = gtmPlan.channel_strategy[i];
  if (!c.channel || !c.rationale) {
    throw new Error('SCHEMA_VIOLATION: channel_strategy[' + i + '] must have channel and rationale.');
  }
  if (!PRIORITY_ENUM.includes(c.priority)) {
    // Auto-correct unknown priority to secondary
    console.warn('SCHEMA_WARN: channel_strategy[' + i + '].priority "' + c.priority + '" not valid — set to secondary');
    cloudWarnings.push('channel_strategy[' + i + '].priority auto-corrected to secondary');
    c.priority = 'secondary';
  }
}

// acquisition_priorities: array, min 1
if (!Array.isArray(gtmPlan.acquisition_priorities) || gtmPlan.acquisition_priorities.length < 1) {
  throw new Error('SCHEMA_VIOLATION: acquisition_priorities must be a non-empty array.');
}
for (let i = 0; i < gtmPlan.acquisition_priorities.length; i++) {
  const a = gtmPlan.acquisition_priorities[i];
  if (!a.tactic || !a.rationale) {
    throw new Error('SCHEMA_VIOLATION: acquisition_priorities[' + i + '] must have tactic and rationale.');
  }
}

// gtm_narrative: non-empty string, min 100 chars
if (typeof gtmPlan.gtm_narrative !== 'string' || gtmPlan.gtm_narrative.trim().length < 100) {
  throw new Error('SCHEMA_VIOLATION: gtm_narrative must be a non-empty string (min 100 chars).');
}

// kpis: validate if present
if (gtmPlan.kpis && Array.isArray(gtmPlan.kpis)) {
  for (let i = 0; i < gtmPlan.kpis.length; i++) {
    const k = gtmPlan.kpis[i];
    if (!k.kpi || !k.target) {
      throw new Error('SCHEMA_VIOLATION: kpis[' + i + '] must have kpi and target.');
    }
  }
}

// ─── Step 3: Build runtime envelope ──────────────────────────────────────────
const runId       = buildRunId();
const executionTs = new Date().toISOString();

const ch = gtmPlan.channel_strategy || [];
const primaryChannels = ch.filter(function(c) { return c.priority === 'primary'; }).map(function(c) { return c.channel; });

const outputSummary = {
  channel_count:           ch.length,
  primary_channel_count:   primaryChannels.length,
  primary_channels:        primaryChannels,
  acquisition_tactic_count: (gtmPlan.acquisition_priorities || []).length,
  campaign_angle_count:    (gtmPlan.campaign_angles || []).length,
  kpi_count:               (gtmPlan.kpis || []).length,
  test_count:              (gtmPlan.test_plan || []).length,
  execution_risk_count:    (gtmPlan.execution_risks || []).length,
  launch_phases:           Object.keys(gtmPlan.launch_sequence || {}).length,
};

const envelope = {
  run_id:     runId,
  phase:      'gtm-plan',
  project_id: projectId,
  timestamp:  executionTs,
  cloud_mode: cloudMode,
  validation: {
    result:    'PASS',
    errors:    [],
    warnings:  cloudWarnings,
  },
  diagnostics: {
    output_summary: outputSummary,
  },
  lineage: {
    depends_on: ['build-content-strategy', 'build-offer-architecture', 'build-strategy-synthesis'],
    produced_by: 'build-gtm-plan',
  },
};

return [{
  json: {
    project_id:    projectId,
    artifact_name: 'gtm-plan',
    artifact_path: null,
    gtm_plan:      gtmPlan,
    runtime_config: runtimeConfig,
    status:        'SUCCESS',
    cloud_mode:    cloudMode,
    cloud_warnings: cloudWarnings,
    notes:         [],
    envelope:      envelope,
  },
}];
